139→#define BENCH_FUNC_2(name, arg1, arg2) do {                           \
140→    volatile double _a1 = (arg1), _a2 = (arg2);                       \
141→    startPFM();                                                        \
142→    for (int _n = 0; _n < NITER; _n++) {                               \
143→        volatile double _r = name(_a1, _a2);                           \
144→        (void)_r;                                                      \
145→    }                                                                  \
146→    stopPFM();                                                         \
147→    printf("%s,%llu,%llu,%d\n",                                        \
148→           #name,                                                      \
149→           (unsigned long long)pfm_cycle,                              \
150→           (unsigned long long)pfm_inst,                               \
151→           NITER);                                                     \
152→} while (0)
153→
154→#define BENCH_FUNCF_1(name, arg) do {                                 \
155→    volatile float _a = (arg);                                         \
156→    startPFM();                                                        \
157→    for (int _n = 0; _n < NITER; _n++) {                               \
158→        volatile float _r = name(_a);                                  \
159→        (void)_r;                                                      \
160→    }                                                                  \
161→    stopPFM();                                                         \
162→    printf("%s,%llu,%llu,%d\n",                                        \
163→           #name,                                                      \
164→           (unsigned long long)pfm_cycle,                              \
165→           (unsigned long long)pfm_inst,                               \
166→           NITER);                                                     \
167→} while (0)
168→
169→#define BENCH_FUNCF_2(name, arg1, arg2) do {                          \
170→    volatile float _a1 = (arg1), _a2 = (arg2);                        \
171→    startPFM();                                                        \
