  6→OUTPUT_FORMAT("elf64-littleriscv", "elf64-littleriscv",
  7→              "elf64-littleriscv")
  8→OUTPUT_ARCH(riscv)
  9→ENTRY(_start)
 10→SEARCH_DIR("/local/sqa/Jenkins/workspace/build-system-3/toolchain/nds64le-elf-mculib-v5d/riscv64-elf/lib");
 11→SECTIONS
 12→{
 13→  /* Read-only sections, merged into text segment: */
 14→  PROVIDE (__executable_start = SEGMENT_START("text-segment", 0x10000)); . = SEGMENT_START("text-segment", 0x10000) + SIZEOF_HEADERS;
 15→  .interp         : { *(.interp) }
 16→  .note.gnu.build-id  : { *(.note.gnu.build-id) }
 17→  .hash           : { *(.hash) }
 18→  .gnu.hash       : { *(.gnu.hash) }
 19→  .dynsym         : { *(.dynsym) }
 20→  .dynstr         : { *(.dynstr) }
 21→  .gnu.version    : { *(.gnu.version) }
 22→  .gnu.version_d  : { *(.gnu.version_d) }
 23→  .gnu.version_r  : { *(.gnu.version_r) }
 24→  .rela.dyn       :
 25→    {
 26→      *(.rela.init)
 27→      *(.rela.text .rela.text.* .rela.gnu.linkonce.t.*)
 28→      *(.rela.fini)
 29→      *(.rela.rodata .rela.rodata.* .rela.gnu.linkonce.r.*)
