    BENCH_FUNC_1(acos,   0.5);
    BENCH_FUNC_1(acosh,  2.0);
    BENCH_FUNC_1(asin,   0.5);
    BENCH_FUNC_1(asinh,  1.0);
    BENCH_FUNC_1(atan,   1.0);
    BENCH_FUNC_2(atan2,  1.0, 1.0);
    BENCH_FUNC_1(atanh,  0.5);
    BENCH_FUNC_1(cbrt,   8.0);
    BENCH_FUNC_1(cos,    1.0);
    BENCH_FUNC_1(cosh,   1.0);
    BENCH_FUNC_1(erf,    1.0);
    BENCH_FUNC_1(erfc,   1.0);
    BENCH_FUNC_1(exp,    1.0);
    BENCH_FUNC_1(exp2,   3.0);
    BENCH_FUNC_1(expm1,  0.5);
    BENCH_FUNC_2(hypot,  3.0, 4.0);
    BENCH_FUNC_1(j0,     1.0);
    BENCH_FUNC_1(j1,     1.0);
    BENCH_FUNC_1(log,    2.0);
    BENCH_FUNC_1(log10,  100.0);
    BENCH_FUNC_1(log1p,  0.5);
    BENCH_FUNC_1(log2,   8.0);
    BENCH_FUNC_2(pow,    2.0, 10.0);
    BENCH_FUNC_1(sin,    1.0);
    BENCH_FUNC_1(sinh,   1.0);
    BENCH_FUNC_1(sqrt,   2.0);
    BENCH_FUNC_1(tan,    1.0);
    BENCH_FUNC_1(tanh,   1.0);
    BENCH_FUNC_1(tgamma, 3.5);
    BENCH_FUNC_1(lgamma, 3.5);

    /* ---- single-precision (float) ---- */
    BENCH_FUNCF_1(acosf,   0.5f);
    BENCH_FUNCF_1(acoshf,  2.0f);
    BENCH_FUNCF_1(asinf,   0.5f);
    BENCH_FUNCF_1(asinhf,  1.0f);
    BENCH_FUNCF_1(atanf,   1.0f);
    BENCH_FUNCF_2(atan2f,  1.0f, 1.0f);
    BENCH_FUNCF_1(atanhf,  0.5f);
    BENCH_FUNCF_1(cbrtf,   8.0f);
    BENCH_FUNCF_1(cosf,    1.0f);
    BENCH_FUNCF_1(coshf,   1.0f);
    BENCH_FUNCF_1(erff,    1.0f);
    BENCH_FUNCF_1(erfcf,   1.0f);
    BENCH_FUNCF_1(expf,    1.0f);
    BENCH_FUNCF_1(exp2f,   3.0f);
    BENCH_FUNCF_1(expm1f,  0.5f);
    BENCH_FUNCF_2(hypotf,  3.0f, 4.0f);
    BENCH_FUNCF_1(j0f,     1.0f);
    BENCH_FUNCF_1(j1f,     1.0f);
    BENCH_FUNCF_1(logf,    2.0f);
    BENCH_FUNCF_1(log10f,  100.0f);
    BENCH_FUNCF_1(log1pf,  0.5f);
    BENCH_FUNCF_1(log2f,   8.0f);
    BENCH_FUNCF_2(powf,    2.0f, 10.0f);
