/*
 * Cycle-count benchmark for libm functions on RISC-V FPGA.
 *
 * Uses the same performance counter approach as libnn (nds_pfcounter.h):
 * inhibit all machine counters, reset mcycle/minstret to zero, re-enable,
 * run the function, then inhibit and read the counters.
 *
 * Outputs CSV to stdout via semihosting/UART.
 *
 * Build:
 *   riscv64-elf-gcc -Os -o bench-math.elf bench-math.c \
 *       --specs=picolibc.specs -T ae350.ld -lm -lc -lsemihost
 *
 * Run on FPGA via GDB:
 *   riscv64-elf-gdb -batch -x run-bench.gdb bench-math.elf
 */

#include <stdio.h>
#include <math.h>
#include <stdint.h>

/* ---------- CSR definitions ---------- */

/* Standard RISC-V CSRs */
#define CSR_MCYCLE          0xB00
#define CSR_MINSTRET        0xB02
#define CSR_MCOUNTINHIBIT   0x320
#if __riscv_xlen == 32
#define CSR_MCYCLEH         0xB80
#define CSR_MINSTRETH       0xB82
#endif

/* Andes-specific CSRs for overflow detection */
#define CSR_MMSC_CFG        0xFC2
#define CSR_MCOUNTEROVF     0xFC9

/* ---------- CSR access helpers ---------- */

#define csr_write(csr, val) \
    __asm__ volatile("csrw %0, %1" :: "i"(csr), "r"(val))

#define csr_read(csr, val) \
    __asm__ volatile("csrr %0, %1" : "=r"(val) : "i"(csr))

/* ---------- performance counter globals ---------- */

static uint64_t pfm_cycle;
static uint64_t pfm_inst;

/* ---------- performance counter functions ---------- */

/*
 * Inhibit all machine counters, reset mcycle and minstret to zero,
 * then re-enable all counters.  Same as libnn _startPFM().
 */
static inline void startPFM(void)
{
    /* Inhibit all machine counters */
    csr_write(CSR_MCOUNTINHIBIT, 0x7F);

    /* Reset counters to zero */
#if __riscv_xlen == 32
    csr_write(CSR_MINSTRET, 0);
    csr_write(CSR_MINSTRETH, 0);
    csr_write(CSR_MCYCLE, 0);
    csr_write(CSR_MCYCLEH, 0);
#else
    csr_write(CSR_MINSTRET, 0);
    csr_write(CSR_MCYCLE, 0);
#endif

    /* Enable all machine counters */
    csr_write(CSR_MCOUNTINHIBIT, 0);
}

/*
 * Inhibit all machine counters, read mcycle and minstret,
 * check for overflow, then re-enable counters.  Same as libnn _stopPFM().
 */
static inline void stopPFM(void)
{
    /* Inhibit all machine counters */
    csr_write(CSR_MCOUNTINHIBIT, 0x7F);

    /* Read performance counters */
#if __riscv_xlen == 32
    uint32_t inst_lo, inst_hi, cycle_lo, cycle_hi;
    csr_read(CSR_MINSTRET, inst_lo);
    csr_read(CSR_MINSTRETH, inst_hi);
    csr_read(CSR_MCYCLE, cycle_lo);
    csr_read(CSR_MCYCLEH, cycle_hi);
    pfm_inst  = ((uint64_t)inst_hi << 32) | inst_lo;
    pfm_cycle = ((uint64_t)cycle_hi << 32) | cycle_lo;
#else
    csr_read(CSR_MINSTRET, pfm_inst);
    csr_read(CSR_MCYCLE, pfm_cycle);
#endif

    /* Check counter overflow (Andes extension) */
    unsigned long mmsc_cfg;
    csr_read(CSR_MMSC_CFG, mmsc_cfg);
    if (mmsc_cfg & 0x8000) {
        unsigned long ovf;
        csr_read(CSR_MCOUNTEROVF, ovf);
        if (ovf & 0x4)
            printf("WARNING: instruction counter overflow!\n");
        if (ovf & 0x1)
            printf("WARNING: cycle counter overflow!\n");
    }

    /* Re-enable all machine counters */
    csr_write(CSR_MCOUNTINHIBIT, 0);
}

/* ---------- benchmark harness ---------- */

/*
 * NITER: number of iterations per function.
 * Increase for more stable results; decrease if FPGA is slow.
 */
#define NITER 1000

/* Prevent the compiler from optimising the call away. */
#define BENCH_FUNC_1(name, arg) do {                                  \
    volatile double _a = (arg);                                        \
    startPFM();                                                        \
    for (int _n = 0; _n < NITER; _n++) {                               \
        volatile double _r = name(_a);                                 \
        (void)_r;                                                      \
    }                                                                  \
    stopPFM();                                                         \
    printf("%s,%llu,%llu,%d\n",                                        \
           #name,                                                      \
           (unsigned long long)pfm_cycle,                              \
           (unsigned long long)pfm_inst,                               \
           NITER);                                                     \
} while (0)

#define BENCH_FUNC_2(name, arg1, arg2) do {                           \
    volatile double _a1 = (arg1), _a2 = (arg2);                       \
    startPFM();                                                        \
    for (int _n = 0; _n < NITER; _n++) {                               \
        volatile double _r = name(_a1, _a2);                           \
        (void)_r;                                                      \
    }                                                                  \
    stopPFM();                                                         \
    printf("%s,%llu,%llu,%d\n",                                        \
           #name,                                                      \
           (unsigned long long)pfm_cycle,                              \
           (unsigned long long)pfm_inst,                               \
           NITER);                                                     \
} while (0)

#define BENCH_FUNCF_1(name, arg) do {                                 \
    volatile float _a = (arg);                                         \
    startPFM();                                                        \
    for (int _n = 0; _n < NITER; _n++) {                               \
        volatile float _r = name(_a);                                  \
        (void)_r;                                                      \
    }                                                                  \
    stopPFM();                                                         \
    printf("%s,%llu,%llu,%d\n",                                        \
           #name,                                                      \
           (unsigned long long)pfm_cycle,                              \
           (unsigned long long)pfm_inst,                               \
           NITER);                                                     \
} while (0)

#define BENCH_FUNCF_2(name, arg1, arg2) do {                          \
    volatile float _a1 = (arg1), _a2 = (arg2);                        \
    startPFM();                                                        \
    for (int _n = 0; _n < NITER; _n++) {                               \
        volatile float _r = name(_a1, _a2);                            \
        (void)_r;                                                      \
    }                                                                  \
    stopPFM();                                                         \
    printf("%s,%llu,%llu,%d\n",                                        \
           #name,                                                      \
           (unsigned long long)pfm_cycle,                              \
           (unsigned long long)pfm_inst,                               \
           NITER);                                                     \
} while (0)

int main(void)
{
    printf("function,total_cycles,total_instret,iterations\n");

    /* ---- double-precision ---- */
    BENCH_FUNC_1(acos,   0.5);
    BENCH_FUNC_1(acosh,  2.0);
    BENCH_FUNC_1(asin,   0.5);
    BENCH_FUNC_1(asinh,  1.0);
    BENCH_FUNC_1(atan,   1.0);
    BENCH_FUNC_2(atan2,  1.0, 1.0);
    BENCH_FUNC_1(atanh,  0.5);
    BENCH_FUNC_1(cbrt,   8.0);
    BENCH_FUNC_1(cos,    1.0);
    BENCH_FUNC_1(cosh,   1.0);
    BENCH_FUNC_1(erf,    1.0);
    BENCH_FUNC_1(erfc,   1.0);
    BENCH_FUNC_1(exp,    1.0);
    BENCH_FUNC_1(exp2,   3.0);
    BENCH_FUNC_1(expm1,  0.5);
    BENCH_FUNC_2(hypot,  3.0, 4.0);
    BENCH_FUNC_1(j0,     1.0);
    BENCH_FUNC_1(j1,     1.0);
    BENCH_FUNC_1(log,    2.0);
    BENCH_FUNC_1(log10,  100.0);
    BENCH_FUNC_1(log1p,  0.5);
    BENCH_FUNC_1(log2,   8.0);
    BENCH_FUNC_2(pow,    2.0, 10.0);
    BENCH_FUNC_1(sin,    1.0);
    BENCH_FUNC_1(sinh,   1.0);
    BENCH_FUNC_1(sqrt,   2.0);
    BENCH_FUNC_1(tan,    1.0);
    BENCH_FUNC_1(tanh,   1.0);
    BENCH_FUNC_1(tgamma, 3.5);
    BENCH_FUNC_1(lgamma, 3.5);

    /* ---- single-precision (float) ---- */
    BENCH_FUNCF_1(acosf,   0.5f);
    BENCH_FUNCF_1(acoshf,  2.0f);
    BENCH_FUNCF_1(asinf,   0.5f);
    BENCH_FUNCF_1(asinhf,  1.0f);
    BENCH_FUNCF_1(atanf,   1.0f);
    BENCH_FUNCF_2(atan2f,  1.0f, 1.0f);
    BENCH_FUNCF_1(atanhf,  0.5f);
    BENCH_FUNCF_1(cbrtf,   8.0f);
    BENCH_FUNCF_1(cosf,    1.0f);
    BENCH_FUNCF_1(coshf,   1.0f);
    BENCH_FUNCF_1(erff,    1.0f);
    BENCH_FUNCF_1(erfcf,   1.0f);
    BENCH_FUNCF_1(expf,    1.0f);
    BENCH_FUNCF_1(exp2f,   3.0f);
    BENCH_FUNCF_1(expm1f,  0.5f);
    BENCH_FUNCF_2(hypotf,  3.0f, 4.0f);
    BENCH_FUNCF_1(j0f,     1.0f);
    BENCH_FUNCF_1(j1f,     1.0f);
    BENCH_FUNCF_1(logf,    2.0f);
    BENCH_FUNCF_1(log10f,  100.0f);
    BENCH_FUNCF_1(log1pf,  0.5f);
    BENCH_FUNCF_1(log2f,   8.0f);
    BENCH_FUNCF_2(powf,    2.0f, 10.0f);
    BENCH_FUNCF_1(sinf,    1.0f);
    BENCH_FUNCF_1(sinhf,   1.0f);
    BENCH_FUNCF_1(sqrtf,   2.0f);
    BENCH_FUNCF_1(tanf,    1.0f);
    BENCH_FUNCF_1(tanhf,   1.0f);
    BENCH_FUNCF_1(tgammaf, 3.5f);
    BENCH_FUNCF_1(lgammaf, 3.5f);

    return 0;
}

