 * Filter: compile with -DBENCH_FILTER=sinf to benchmark only sinf.
 * Omit to benchmark all functions.
 */
#define _BENCH_STR(x) #x
#define BENCH_STR(x) _BENCH_STR(x)

static inline int bench_skip(const char *name)
{
#ifdef BENCH_FILTER
    return strcmp(name, BENCH_STR(BENCH_FILTER)) != 0;
#else
    (void)name;
    return 0;
#endif
}

/* Prevent the compiler from optimising the call away. */
